import { Component, Host, h, Prop, Event, EventEmitter, State, Watch, Fragment } from '@stencil/core';
import { TreeMenuItem } from './menu-item.interface';
import cloneDeep from 'lodash/cloneDeep';
import {
  findItemInArrayByUuid,
  getAllSelectedChildren,
  getInvalidChildCount,
  setDisplayChildrenStatus,
  setParentStatus
}
  from './menu-item-utils';
import isEqual from 'lodash.isequal';
import { isNullOrUndefined, removeCircularReplacer } from '@src/utils/mx-utils/utils';

@Component({
  tag: 'mx-menu-item',
  styleUrl: 'mx-menu-item.css'
})
export class MxMenuItem {
  /** Sets menu item for ngmodel. */
  @Prop({ mutable: true }) itemSelected: TreeMenuItem[] = [];
  /** Hold the information about of the Menu item. */
  @Prop({ mutable: true }) item: TreeMenuItem;
  /** Set the label of menu item. */
  @Prop() readonly label: string;
  /** Disable the menu item. */
  @Prop() readonly isDisabled: boolean = false;
  /** Show/hide the checkbox for menu item. */
  @Prop() readonly showCheckbox: boolean = false;
  /** Will show title for each element with label value. */
  @Prop() readonly showTitle: boolean = false;
  /** Show checkbox in compact size. */
  @Prop() readonly compactCheckbox: boolean = false;
  /** Show/hide the caret. */
  @Prop() readonly hideCaret: boolean = false;
  /** Show/hide the length of children of menu. */
  @Prop() readonly showChildCount: boolean = false;
  /** Show/hide the children of menu item. */
  @Prop({ mutable: true }) displayChildren = true;

  @Watch('displayChildren')
  handleDisplayChildren(newValue: boolean) {
    setDisplayChildrenStatus(this._item, newValue);
  }

  /** Emit the complete tree structure. */
  @Prop() readonly emitTree: boolean = false;

  /** Emitted when the user selects menu item. */
  @Event() menuItemSelected: EventEmitter<TreeMenuItem>;
  /** Emitted when the user clicks to open the menu item and display child menu. */
  @Event() menuItemOpened: EventEmitter<TreeMenuItem>;
  /** Emitted when the user clicks to close the menu item and hide child menu. */
  @Event() menuItemClosed: EventEmitter<TreeMenuItem>;
  /** Emitted with menu items detail when the user clicks on menu item. */
  @Event() menuItemEvent: EventEmitter<any>;

  // We need a separate event for ngModel because we don't want to break components that are already using "menuItemSelected"
  /** DO NOT USE DIRECTLY. THIS IS NOT MEANT FOR CONSUMER USE.
   * Its sole purpose is to enable ngModel support to be used in Angular applications.
   * This event is emitted when the user selects a menu item or its children. */
  @Event() ngModelMenuItemSelected: EventEmitter<TreeMenuItem[]>;

  @State() _itemValue: TreeMenuItem;

  // We need to handle item updates differently depending on if they were done by users or externally.
  private externalItemChange = true;

  set _item(item: TreeMenuItem) {
    if (isNullOrUndefined(item)) {
      return;
    }
    // We don't want any additional logic applied to the "Select All" item.
    if (item.label === 'Select All' && item.value === 'all') {
      this._itemValue = item;
      this.item = item;
      return;
    }
    this.initiateItem(item);

    if (!isNullOrUndefined(item.children) && this.externalItemChange) {
      const childCount = item.children.length;
      const selectedChildCount = item.children.filter((it) => it.selected).length;

      const disabledCount = item.children.filter((it) => it.disabled).length;
      if (disabledCount === childCount) {
        item.disabled = true;
      }
      if (item.selected) {

        if (disabledCount > 0 && selectedChildCount < childCount) {
          item.selected = false;
          const notSelectedChildCount =
            item.children.filter((it) => !isNullOrUndefined(it.selected) && !it.selected).length;
          if (notSelectedChildCount === selectedChildCount) {
            item.indeterminate = disabledCount !== childCount;
          } else {
            item.indeterminate = false;
          }
          this.setChildrenStatus(item.children, true);
        }
      }

      if (selectedChildCount === childCount) {
        item.selected = true;
        item.indeterminate = false;
      } else if (selectedChildCount > 0 && selectedChildCount < childCount) {
        item.selected = false;
        item.indeterminate = true;
      }

      if (disabledCount > 0 && disabledCount !== childCount) {
        if (selectedChildCount > 0 && selectedChildCount < childCount) {
          item.indeterminate = true;
        } else if (selectedChildCount === childCount) {
          if (selectedChildCount !== childCount) {
            item.selected = false;
          }
        }
      }
      this.disableChildrenOfDisabledParent(item);

      const disabledCountUpdated = item.children.filter((it) => it.disabled).length;
      const selectedChildCountUpdated = item.children.filter((it) => it.selected).length;

      if (disabledCountUpdated === childCount) {
        item.disabled = true;
      }
      item.indeterminate = selectedChildCountUpdated > 0 && selectedChildCountUpdated < childCount;
      if (item.selected) {
        this.setChildrenStatus(item.children, true);
      }
      if (item.indeterminate) {
        this.selectChildrenOfSelectedParent(item);
      }
    }
    if (!isNullOrUndefined(item.children)) {
      this.propagateSelectedStatuses(item.children);
      this.sanitizeSelectedItems(item);
      this.sanitizeIndeterminateItems(item);
    }
    if (!isNullOrUndefined(item.displayChildren)) {
      this.displayChildren = item.displayChildren;
    }
    this._itemValue = item;
    this.item = item;

    // If we don't remove the circular reference with the "parent" property, then it will have an infinite loop.
    // We need to keep track of all the selected children, so we can update "itemSelected" for ngModel support.
    const allSelectedChildren = [];
    getAllSelectedChildren(removeCircularReplacer(item), allSelectedChildren);
    if (!isEqual(this.itemSelected, allSelectedChildren)) {
      this.itemSelected = allSelectedChildren;
    }
  }

  get _item() {
    return this._itemValue;
  }

  @Watch('itemSelected')
  handleItemSelectedChange(newValue: TreeMenuItem[]) {
    if (isNullOrUndefined(newValue)) {
      return;
    }
    if (!this.externalItemChange) {
      // If we mutated the item internally, then we do not need to do any additional logic -- just emit the event.
      // Do not use our standard menuItemSelected event, as we need to use arrays. Changing that functionality will break other components.
      this.ngModelMenuItemSelected.emit(newValue);
    } else {
      if (!isNullOrUndefined(this._item)) {
        this.updatedItemWithSelectedItems(newValue);
        this.ngModelMenuItemSelected.emit(newValue);
      }
    }
  }


  @Watch('item')
  handleItemChange(newValue: TreeMenuItem) {
    this.initializeDisplayChildrenStatus(newValue);
    this._item = newValue;
  }

  constructor() {
    if (!isNullOrUndefined(this.item)) {
      this.initializeDisplayChildrenStatus(this.item);
      this._item = this.item;
    }
  }

  componentWillLoad() {
    if (!isNullOrUndefined(this._item) && this.itemSelected.length > 0) {
      this.updatedItemWithSelectedItems(this.itemSelected);
    }
  }

  private updatedItemWithSelectedItems(selectedItems: TreeMenuItem[]) {
    if (!isNullOrUndefined(selectedItems)) {
      if (selectedItems.length === 0) {
        this._item = { ...this._item, selected: false, indeterminate: false };
        // } else if (selectedItems[0].label === this._item.label && isEqual(selectedItems[0].value, this._item.value)) {
      } else if (isEqual(selectedItems[0].uuid, this._item.uuid)) {
        this._item = { ...this._item, selected: true, indeterminate: false };
      } else {
        // // Un-select all items before selecting the new item.
        // unselectItemAndChildren(this._item);
        selectedItems.forEach((item) => {
          const findItem = findItemInArrayByUuid(this._item.children, item.uuid);
          if (!isNullOrUndefined(findItem)) {
            findItem.selected = true;
            findItem.indeterminate = false;
          }
        });
        this._item = { ...this._item };
      }
    }
  }

  private initializeDisplayChildrenStatus(item: TreeMenuItem) {
    if (!isNullOrUndefined(item) &&
      !isNullOrUndefined(item.children) &&
      item.children.length > 0 &&
      isNullOrUndefined(item.displayChildren)) {
      item.displayChildren = this.displayChildren;
      item.children.forEach((child) => {
        this.initializeDisplayChildrenStatus(child);
      });
    }
  }

  private propagateSelectedStatuses(items: TreeMenuItem[]) {
    items?.forEach((it) => {
      if (it.selected) {
        setParentStatus(it.parent);
      } else if (!isNullOrUndefined(it.children)) {
        this.propagateSelectedStatuses(it.children);
      }
    });
  }

  // Let's verify that a selected item is actually selected(and not indeterminate)
  private sanitizeSelectedItems(item: TreeMenuItem) {
    item.children?.forEach((it) => {
      if (it.selected) {
        const isSelected = true;
        const isActuallySelected = this.isParentItemActuallySelected(it, isSelected);
        if (!isActuallySelected) {
          it.selected = false;
          it.indeterminate = true;
        }
      }
    });
  }

  // Let's verify that an indeterminate item's selected children(and nested chilcdren) are actually selected
  private sanitizeIndeterminateItems(item: TreeMenuItem) {
    item.children?.forEach((it) => {
      if (it.indeterminate) {
        it.children?.forEach((child) => {
          if (child.selected && !isNullOrUndefined(child.children)) {
            this.setChildrenStatus(child.children, true);
          }
          this.sanitizeIndeterminateItems(child);
        });
      }
    });
  }

  private isParentItemActuallySelected(item: TreeMenuItem, selectedStatus: boolean) {
    item.children?.forEach((it) => {

      if (!it.selected || it.indeterminate) {
        if (it.disabled) {
          const selectedCount = it.children?.length;
          const disabledCount = it.children?.filter((child) => child.disabled).length;
          selectedStatus = disabledCount > 0 && disabledCount === selectedCount;
        } else {
          selectedStatus = false;
        }
      }
      if (selectedStatus) {
        this.isParentItemActuallySelected(it, selectedStatus);
      }
    });
    return selectedStatus;
  }

  private selectChildrenOfSelectedParent(item: TreeMenuItem) {
    item.children?.map((it) => {
      if (it.selected && !isNullOrUndefined(it.children)) {
        this.setChildrenStatus(it.children, true);
      }
    });
  }

  private disableChildrenOfDisabledParent(item: TreeMenuItem) {
    const childCount = item?.children.length;
    let disabledChildCount = 0;
    const selectedChildCount = item?.children.filter((it) => it.selected).length;

    item.children?.forEach((it) => {
      if (it.disabled) {
        this.disableAllChildren(it);
        disabledChildCount++;
      } else if (!isNullOrUndefined(it.children)) {
        this.disableChildrenOfDisabledParent(it);
      }
    });
    if (disabledChildCount === childCount) {
      item.disabled = true;
      item.selected = childCount === selectedChildCount;
      item.indeterminate = !item.selected && selectedChildCount > 0;
    }
  }

  private setAllParents(item: TreeMenuItem) {
    item?.children.forEach((child) => {
      child.parent = item;
      if (!isNullOrUndefined(child.children)) {
        this.setAllParents(child);
      }
    });
  }

  private initiateItem(item: TreeMenuItem) {
    if (!isNullOrUndefined(item) && !isNullOrUndefined(item.children)) {
      item.selected = isNullOrUndefined(item.selected) ? false : item.selected;
      item.indeterminate = isNullOrUndefined(item.indeterminate) ? false : item.indeterminate;
      item.disabled = isNullOrUndefined(item.disabled) ? false : item.disabled;
      if (item.disabled) {
        this.disableAllChildren(item);
      }
      this.setAllParents(item);
      item.children.forEach((child: TreeMenuItem) => {
        child.selected = isNullOrUndefined(child.selected) ? false : child.selected;
        child.indeterminate = isNullOrUndefined(child.indeterminate) ? false : child.indeterminate;
        child.disabled = isNullOrUndefined(child.disabled) ? false : child.disabled;
      });
    }
  }

  private disableAllChildren(item: TreeMenuItem) {
    if (!isNullOrUndefined(item.children)) {
      item.children.forEach((child) => {
        child.disabled = true;
        if (!isNullOrUndefined(child.children)) {
          this.disableAllChildren(child);
        }
      });
    }
  }

  private determineLevel(item: TreeMenuItem) {
    if (isNullOrUndefined(item)) {
      return;
    }
    if (!isNullOrUndefined(item.children) && !isNullOrUndefined(item.parent)) {
      return 'is-both';
    } else if (!isNullOrUndefined(item.parent)) {
      return 'is-child';
    } else {
      return 'is-parent';
    }
  }

  // There is a different function for open() and close() because of UI differences
  private readonly handleOpen = (item: TreeMenuItem) => (event: MouseEvent) => {
    event.preventDefault();
    setDisplayChildrenStatus(item, true);
    this._item = { ...this._item };
    this.menuItemOpened.emit(item);
  };

  private readonly handleClose = (item: TreeMenuItem) => (event: MouseEvent) => {
    event.preventDefault();
    setDisplayChildrenStatus(item, false);
    this._item = { ...this._item };
    this.menuItemClosed.emit(item);
  };

  private isKDSLabel(event) {
    return (
      event.target && (event.target.classList.contains('kds-Label') || event.target.classList.contains('disabled-text'))
    );
  }

  private isKDSIcon(event) {
    return event.target && event.target.classList.contains('kds-Icon');
  }

  private isCheckbox(event) {
    return (
      !this.showCheckbox ||
      (event.target &&
        event.target.firstElementChild &&
        event.target.firstElementChild.classList.contains('no-checkbox'))
    );
  }

  private readonly handleKDSClicks = (item: TreeMenuItem) => (event: MouseEvent) => {
    if (item.disabled || this.isDisabled) {
      return;
    }
    if (this.isKDSLabel(event)) {
      return;
    }
    if (this.isKDSIcon(event)) {
      event.stopPropagation();
      return;
    }
    if (this.isCheckbox(event)) {
      event.stopPropagation();
      return false;
    }
    this.emitSelectStateOnChange(event, item);
  };

  private emitSelectStateOnChange(event, item: TreeMenuItem) {
    if (!isNullOrUndefined(item)) {
      if (event) {
        event.preventDefault();
        event.stopPropagation();
      }
      if (isNullOrUndefined(item.indeterminate) && isNullOrUndefined(item.selected)) {
        item.selected = true;
        item.indeterminate = false;
      } else if (item.indeterminate && !item.selected) {
        this.transitionFromIndeterminateState(item);
      } else if (item.selected) {
        item.selected = false;
        item.indeterminate = false;
      } else {
        item.selected = true;
        item.indeterminate = false;
      }
      this.propagateStatusToParentAndChild(item);
    }

    this.externalItemChange = false;
    this._item = cloneDeep(this._item);
    this.externalItemChange = true;
    this.menuItemSelected.emit(item);
    if (this.emitTree) {
      const result = this.getHierarchy(item);
      this.menuItemEvent.emit(removeCircularReplacer(result));
    } else {
      this.menuItemEvent.emit(removeCircularReplacer(item));
    }
  }

  // It might be better to combine the following 3 functions into one so we only do 1 deep recursion
  // as opposed to several.
  private getAllChildCount(item: TreeMenuItem, omitDisabled = false) {
    let count = 0;
    item.children?.forEach((child) => {
      if (!omitDisabled) {
        count++;
        count += this.getAllChildCount(child);
      } else {
        if (!child.disabled) {
          count++;
          count += this.getAllChildCount(child);
        }
      }
    });
    return count;
  }

  private getSelectedChildCount(item: TreeMenuItem) {
    let count = 0;
    item.children?.forEach((child) => {
      if (child.selected) {
        count++;
      }
      if (!isNullOrUndefined(child.children)) {
        count += this.getSelectedChildCount(child);
      }
    });
    return count;
  }

  private getIndeterminateChildrenCount(item: TreeMenuItem) {
    if (isNullOrUndefined(item.children) || item.children.length < 1) {
      return 0;
    }
    let count = 0;
    item.children.forEach((child) => {
      if (child.indeterminate) {
        count++;
      }
    });
    return count;
  }

  // End
  private transitionFromIndeterminateState(item: TreeMenuItem) {
    if (isNullOrUndefined(item.children)) {
      return;
    }
    let childHasChildren = false;
    item.children.forEach((child) => {
      if (child.children && child.children.length > 0) {
        childHasChildren = true;
      }
    });
    const allChildCount = childHasChildren ? this.getAllChildCount(item, true) : this.getAllChildCount(item, false);
    const selectedChildCount = this.getSelectedChildCount(item);
    const invalidChildCount = getInvalidChildCount(item);
    const indeterminateChildrenCount = this.getIndeterminateChildrenCount(item);
    const invalidAndSelectedAreEqual = selectedChildCount === invalidChildCount;

    if (invalidAndSelectedAreEqual) {
      if (selectedChildCount < allChildCount) {
        item.selected = true;
        item.indeterminate = false;
      }
    } else if (selectedChildCount + indeterminateChildrenCount + invalidChildCount < allChildCount) {
      item.selected = true;
      item.indeterminate = false;
    } else {
      item.selected = false;
      item.indeterminate = false;
    }
  }

  private propagateStatusToParentAndChild(item: TreeMenuItem) {
    if (isNullOrUndefined(item.parent)) {
      if (item.selected && !item.indeterminate) {
        this.setChildrenStatus(item.children, true);
      } else if (!item.indeterminate && !item.selected) {
        this.setChildrenStatus(item.children, false);
      } else if (item.indeterminate && !item.selected) {
        this.setChildrenStatus(item.children, true);
      } else {
        const allChildCount = this.getAllChildCount(item);
        const selectedChildCount = this.getSelectedChildCount(item);
        const invalidChildCount = getInvalidChildCount(item);
        if (selectedChildCount + invalidChildCount < allChildCount) {
          this.setChildrenStatus(item.children, true);
        } else {
          this.setChildrenStatus(item.children, false);
        }
      }
    } else if (isNullOrUndefined(item.children)) {
      setParentStatus(item.parent);
    } else {
      this.setChildrenStatus(item.children, item.selected);
      setParentStatus(item.parent);
    }
    const indeterminateChildrenCount = item.children?.filter((it) => it.indeterminate).length;
    if (indeterminateChildrenCount > 0) {
      item.selected = false;
      item.indeterminate = true;
    }
  }

  private setChildrenStatus(children: TreeMenuItem[], status: boolean) {
    if (isNullOrUndefined(children)) {
      return;
    }
    children
      .filter((child) => {
        return isNullOrUndefined(child.disabled) || !child.disabled;
      })
      .forEach((child) => {
        child.selected = status;
        child.indeterminate = false;
        setParentStatus(child.parent, false);
        this.setChildrenStatus(child.children, status);
      });
  }

  private getHierarchy(item: TreeMenuItem) {
    if (isNullOrUndefined(item.parent)) {
      return item;
    }
    let child = item;
    let parent = item.parent;
    while (true) {
      if (isNullOrUndefined(parent)) {
        parent = child;
        break;
      }
      child = parent;
      parent = parent.parent;
    }
    return parent;
  }

  render() {
    return <Host>{this.renderItem(this._item)}</Host>;
  }

  private renderItem(item: TreeMenuItem) {
    if (isNullOrUndefined(item) && isNullOrUndefined(this.label)) {
      return;
    }

    const itemLevel = this.determineLevel(item);
    const hasChildren = !isNullOrUndefined(item) && !isNullOrUndefined(item.children) && item.children.length > 0;
    const disabled = this.isDisabled || item?.disabled;

    return (
      <li
        class={{
          'menu-item': true,
          'text-tertiary': disabled,
          'mx-tree-list-parent': itemLevel === 'is-parent',
          'mx-tree-list-child': itemLevel === 'is-child',
          'mx-tree-list-both': itemLevel === 'is-both' && !this.hideCaret,
          'mx-tree-list-both pl-32': itemLevel === 'is-both' && this.hideCaret,
          'no-checkbox': !this.showCheckbox
        }}
        role='menuitem'
        tabindex={this.isDisabled || item?.disabled ? -1 : 0}>

        <div title={this.showTitle ? item?.label : ''}
          class={{
            'menu-item-container items-center': true,
            'text-tertiary': disabled
          }}>
          {!this.hideCaret && (
            <div class={{
              'caret-container': true,
              'text-tertiary': disabled
            }}>
              {hasChildren && (
                <Fragment>
                  <button class='kds-DismissalButton kind-prominent variant-minimal mx-kds-icon'
                    style={item.displayChildren && { display: 'none' }}
                    onClick={this.handleOpen(item)}>
                    <kds-icon-caret-right size='s' />
                  </button>
                  <button class='kds-DismissalButton kind-prominent variant-minimal mx-kds-icon'
                    style={!item.displayChildren && { display: 'none' }}
                    onClick={this.handleClose(item)}>
                    <kds-icon-chevron-down size='s' />
                  </button>
                </Fragment>
              )}
            </div>
          )}
          {this.showCheckbox ?
            <div class={{
              'w-full menu-item-checkbox': true,
              'menu-item-checkbox__compact': this.compactCheckbox
            }}>
              <kds-label class='kds-label-text'>
                <kds-checkbox
                  compact={this.compactCheckbox}
                  class='kds-checkbox-item'
                  inner-class='mr-8'
                  disabled={this.isDisabled || item?.disabled}
                  checked={!isNullOrUndefined(item) && item.selected}
                  indeterminate={!isNullOrUndefined(item) && item.indeterminate}
                  onClick={this.handleKDSClicks(item)}></kds-checkbox>
                <div class='truncate'>{item?.label}</div>
                {
                  this.showChildCount && !isNullOrUndefined(item.children) ?
                    <span>({item?.children?.length})</span> :
                    ''
                }
              </kds-label>
              <div>
                <slot />
              </div>
              {item?.important && (
                <span class='dynamic-icon-group'>
                  <kds-icon-error size='m' class='menu-item-important'></kds-icon-error>
                </span>
              )}</div>
            : this.label || item?.label}
        </div>
        {hasChildren && (item.displayChildren || this.hideCaret) && (
          <ul
            class={{
              'menu-child-list': true,
              'pl-0': this.hideCaret
            }}>{this.renderChildren(item)}</ul>
        )}
      </li>
    );
  }

  private renderChildren(item: TreeMenuItem) {
    return !isNullOrUndefined(item.children) ? item.children.map((child) => {
      child.parent = item;
      return this.renderItem(child);
    }) : '';
  }
}
